# Erasure workflow orchestrator
from dataclasses import dataclass, field
from typing import Optional
from enum import Enum
import time, uuid

class ErasureStatus(Enum):
    PENDING = "pending"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"
    BLOCKED_LEGAL_HOLD = "blocked_legal_hold"
    FAILED = "failed"

@dataclass
class ErasureCase:
    case_id: str
    subject_id: str
    request_received_at: float
    deadline: float  # Unix timestamp: 30 days after receipt
    status: ErasureStatus = ErasureStatus.PENDING
    scope: list[dict] = field(default_factory=list)
    completed_systems: list[str] = field(default_factory=list)
    failed_systems: list[str] = field(default_factory=list)
    legal_hold: Optional[str] = None

class ErasureOrchestrator:
    def __init__(self, systems: dict, lineage_client=None):
        # systems: {system_name: erasure_api_client}
        self.systems = systems
        self.lineage = lineage_client

    def create_case(self, subject_id: str) -> ErasureCase:
        now = time.time()
        return ErasureCase(
            case_id=str(uuid.uuid4()),
            subject_id=subject_id,
            request_received_at=now,
            deadline=now + 30 * 24 * 3600,  # 30 days
        )

    def discover_scope(self, case: ErasureCase) -> list[dict]:
        """Find all systems and record IDs containing the subject's data."""
        scope = []
        if self.lineage:
            nodes = self.lineage.find_nodes_for_subject(case.subject_id)
            for node in nodes:
                scope.append({"system": node["system_type"], "record_ids": node["record_ids"]})
        else:
            # Fallback: query each system's subject lookup API
            for system_name, client in self.systems.items():
                records = client.find_subject_records(case.subject_id)
                if records:
                    scope.append({"system": system_name, "record_ids": records})
        case.scope = scope
        return scope

    def execute_erasure(self, case: ErasureCase) -> ErasureStatus:
        """Execute erasure at each system in scope. Returns final status."""
        for item in case.scope:
            system_name = item["system"]
            record_ids = item["record_ids"]
            client = self.systems.get(system_name)
            if client is None:
                case.failed_systems.append(system_name)
                continue
            try:
                client.erase(case.subject_id, record_ids)
                case.completed_systems.append(system_name)
            except Exception as e:
                case.failed_systems.append(system_name)

        if case.failed_systems:
            case.status = ErasureStatus.FAILED
        else:
            case.status = ErasureStatus.COMPLETED
        return case.status

    def verify_erasure(self, case: ErasureCase) -> bool:
        """Re-query each completed system to confirm data is no longer present."""
        for system_name in case.completed_systems:
            client = self.systems[system_name]
            remaining = client.find_subject_records(case.subject_id)
            if remaining:
                return False  # Erasure incomplete
        return True
